def solve(*args):
    if not args:
        return None

    # Validate inputs vs contract
    for arg in args:
        if not isinstance(arg, (int, float)):
            raise ValueError("All inputs must be numbers.")

    # Implement core logic
    result = sum(args) / len(args)

    # Check edge cases
    if len(args) == 1:
        return args[0]

    return result
